sql:
SELECT COUNT(*) AS Base_Vehicle_Count
FROM vehicles
WHERE trim = 'Base';

SELECT make_name 
FROM makes 
WHERE make_id = (SELECT make_id FROM vehicles WHERE vehicle_id = 1);

SELECT vehicle_id
FROM vehicles
WHERE fuel_efficiency_highway = (SELECT MAX(fuel_efficiency_highway) FROM vehicles);

SELECT v.vehicle_id, vt.vehicle_type
FROM vehicles v
INNER JOIN vehicle_types vt ON v.vehicle_type_id = vt.vehicle_type_id;

